BEGIN;

-- Seed anonymized BBS student identities from input_csv/4. BBS audit.csv
-- Code column is preserved in meta.audit_code for filtering/grouping.
ON CONFLICT (student_id) DO UPDATE SET
  last_name = EXCLUDED.last_name,
  first_name = EXCLUDED.first_name,
  status = EXCLUDED.status,
  meta = COALESCE(acad.students.meta, '{}'::jsonb) || COALESCE(EXCLUDED.meta, '{}'::jsonb);

COMMIT;
